import{_ as d,o as a,c as e,a2 as r}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"决策点","description":"","frontmatter":{},"headers":[],"relativePath":"guide/decision-points.md","filePath":"guide/decision-points.md","lastUpdated":1781182843000}'),o={name:"guide/decision-points.md"};function i(l,t,s,n,h,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="决策点" tabindex="-1">决策点 <a class="header-anchor" href="#决策点" aria-label="Permalink to &quot;决策点&quot;">​</a></h1><p>决策点表示角色在回合内允许的<strong>操作数量</strong>。</p><blockquote><p>决策点由游戏平衡常数设置，与角色能力值无关。每个角色的决策点是独立的。</p></blockquote><h2 id="决策点配额" tabindex="-1">决策点配额 <a class="header-anchor" href="#决策点配额" aria-label="Permalink to &quot;决策点配额&quot;">​</a></h2><p>默认情况下，回合内各类行动各限一次，称为&quot;配额&quot;：</p><table tabindex="0"><thead><tr><th>行动</th><th>默认配额</th></tr></thead><tbody><tr><td>普通攻击</td><td>1</td></tr><tr><td>战技</td><td>1</td></tr><tr><td>爆发技</td><td>1</td></tr><tr><td>魔法</td><td>1</td></tr><tr><td>物品</td><td>1</td></tr></tbody></table><p>被动技能和特效可以操作决策点及其配额，赋予动态策略性。</p><div class="info custom-block"><p class="custom-block-title">临时全能配额</p><p>允许在没有对应配额时，将全能配额转换为指定配额使用。临时配额仅当回合有效。</p></div><h2 id="初始化与补充" tabindex="-1">初始化与补充 <a class="header-anchor" href="#初始化与补充" aria-label="Permalink to &quot;初始化与补充&quot;">​</a></h2><table tabindex="0"><thead><tr><th>规则</th><th>数值</th></tr></thead><tbody><tr><td>初始决策点上限</td><td>2</td></tr><tr><td>回合开始时补充</td><td>上限的一半（向下取整，至少 1）</td></tr><tr><td>每轮到自己 Turn</td><td>上限 +1（最多 7）</td></tr><tr><td>完全行动不能/行动受限</td><td>仅补充上限的 1/4（向下取整，至少 1）</td></tr></tbody></table><h2 id="使用消耗" tabindex="-1">使用消耗 <a class="header-anchor" href="#使用消耗" aria-label="Permalink to &quot;使用消耗&quot;">​</a></h2><table tabindex="0"><thead><tr><th>行动</th><th>消耗</th></tr></thead><tbody><tr><td>普通攻击</td><td>1 决策点</td></tr><tr><td>战技 / 魔法</td><td>2 决策点</td></tr><tr><td>物品</td><td>1 决策点</td></tr><tr><td>回合内爆发技</td><td>2 决策点</td></tr><tr><td>回合外爆发技</td><td>3 决策点</td></tr></tbody></table><h2 id="硬直时间-多次行动" tabindex="-1">硬直时间（多次行动） <a class="header-anchor" href="#硬直时间-多次行动" aria-label="Permalink to &quot;硬直时间（多次行动）&quot;">​</a></h2><p>当回合内行动次数 &gt; 1 时：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回合结束时硬直时间 = 最长一次行动的硬直时间 + 本回合已使用的决策点数量</span></span></code></pre></div><p>单次行动或放弃行动不适用此规则。</p><h2 id="特殊情况" tabindex="-1">特殊情况 <a class="header-anchor" href="#特殊情况" aria-label="Permalink to &quot;特殊情况&quot;">​</a></h2><ul><li>回合内吟唱魔法 → 直接结束回合</li><li>预释放爆发技 → 不适用上述规则</li><li>先行动再吟唱 → 硬直时间累计到吟唱结算的回合</li></ul>',18)])])}const u=d(o,[["render",i]]);export{b as __pageData,u as default};
